mapper.sql:
FROM TWORK_MST_STORE A
LEFT OUTER JOIN TWORK_MST_CT B
	ON B.CTKEY = A.CTKEY
LEFT OUTER JOIN TWORK_MST_OW C
	ON C.OWKEY = A.OWKEY



		AND	#{SEARCH_CONDITION}



		AND	A.CTKEY = #{ctkey}



		AND	A.OWKEY = #{owkey}



		AND	A.DCKEY = #{dckey}



		AND	A.STORE_KEY = #{storeKey}

mapper.select:
/* wms-master-store-sql-oracle.xml - selectStore */
SELECT A.CTKEY , B.CTNAME , A.OWKEY , C.OWNAME , A.STORE_KEY , A.STORE_NAME , A.OLD_STORE_KEY , A.TEL1 , A.TEL2 , A.ADDRESS1 , A.ADDRESS2 , A.STARTDATE , A.CLOSEDATE , A.LDG_TIME , A.UNLDG_TIME , A.FCTYPE , A.OWNER_NAME , A.DCKEY , A.REGDATE , A.REGNO , A.KTG_AREA_CD , A.URKEY AS SV_CD , A.SV_NM , A.SV_TEL , A.ADDRID , A.DLDAY , A.ZIPCODE , A.ISMANAGESTORE , A.CUST_GRADE , A.MAXOVERQTY , A.DELYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY
ORDER BY A.UPDATEDATE DESC

mapper.update:
UPDATE
    TWORK_MST_STORE
SET
	  MAXOVERQTY = #{maxoverqty}
	, ISMANAGESTORE = #{ismanagestore}
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND DCKEY = #{dckey}
AND STORE_KEY = #{storeKey}
